import React from "react";
import { Link, useNavigate } from "react-router-dom";

function Navbar() {
  const navigate = useNavigate();

  return (
    <nav style={{ display: "flex", justifyContent: "space-between", padding: "10px 20px", background: "#eee" }}>
      <div>
        <Link to="/" style={{ margin: "0 10px" }}>Home</Link>
        <Link to="/experience" style={{ margin: "0 10px" }}>Experience</Link>
        <Link to="/services" style={{ margin: "0 10px" }}>Services</Link>
      </div>

      <div>
        {/* Buttons for login/signup */}
        <button onClick={() => navigate("/login")} style={{ margin: "0 5px" }}>Login</button>
        <button onClick={() => navigate("/signup")} style={{ margin: "0 5px" }}>Sign Up</button>
      </div>
    </nav>
  );
}

export default Navbar;
